import streamlit as st

st.markdown("<h2 style='text-align: center;'>Antes de partir eu quero...</h1>", unsafe_allow_html=True)

if "tarefas" not in st.session_state:
    st.session_state.tarefas = []

nova_tarefa = st.text_input("Nova tarefa")

if st.button("Adicionar"):
    if nova_tarefa:
        st.session_state.tarefas.append({"texto": nova_tarefa, "feito": False})


st.divider()

st.subheader("Metas a realizar")

for i, tarefa in enumerate(st.session_state.tarefas):
    if not tarefa["feito"]:
        col1, col2 = st.columns([4, 1])

        with col1:
            marcado = st.checkbox(
                tarefa["texto"],
                value=tarefa["feito"],
                key=f"pendente_{i}"
            )
            if marcado != tarefa["feito"]:
                tarefa["feito"] = marcado
                st.rerun()

        with col2:
            if st.button("❌", key=f"del_pendente_{i}"):
                st.session_state.tarefas.pop(i)
                st.rerun()

st.divider()

st.subheader("Metas cumpridas")

for i, tarefa in enumerate(st.session_state.tarefas):
    if tarefa["feito"]:
        col1, col2 = st.columns([4, 1])

        with col1:
            marcado = st.checkbox(
                tarefa["texto"],
                value=tarefa["feito"],
                key=f"concluida_{i}"
            )
            if marcado != tarefa["feito"]:
                tarefa["feito"] = marcado
                st.rerun()

        with col2:
            if st.button("❌", key=f"del_concluida_{i}"):
                st.session_state.tarefas.pop(i)
                st.rerun()


import streamlit as st
import google.generativeai as genai

genai.configure(api_key=st.secrets["GOOGLE_API_KEY"])

model = genai.GenerativeModel("gemini-2.5-flash")

def gerar_ideia():

    prompt = "Crie uma ideia, resumida a 2 ou 3 palavras, de meta para uma lista de coisas para fazer antes de morrer."

    resposta = model.generate_content(prompt)

    return resposta.text

if st.button("Gerar ideia com IA"):

    ideia = gerar_ideia()

    st.success(ideia)
